const ExcelJS = require\('exceljs'\);
const path = require\('path'\);
const fs = require\('fs'\);

const files = fs.readdirSync\('docs/fichiers-exports/preterme-ird'\).filter\(f => f.endsWith\('.xlsx'\)\);

\(async \(\) => {
  for \(const file of files\) {
    const wb = new ExcelJS.Workbook\(\);
    await wb.xlsx.readFile\(path.join\('docs/fichiers-exports/preterme-ird', file\)\);
    const sheet = wb.worksheets[0];
    console.log\('\\\\n=== FILE:', file, '==='\);
    console.log\('Sheet name:', sheet.name\);
    // Print first 5 rows to understand structure
    let rowCount = 0;
    sheet.eachRow\(\(row, rowNum\) => {
      if \(rowNum <= 5\) {
        const vals = [];
        row.eachCell\({ includeEmpty: true }, \(cell, col\) => {
          vals.push\('[' + col + ']' + JSON.stringify\(cell.value\)\);
        }\);
        console.log\('Row', rowNum, ':', vals.join\(' | '\)\);
        rowCount++;
      }
    }\);
  }
}\)\(\).catch\(console.error\);
